export default function BrandLogoCard({ brand, onSelect }) {
  return (
    <button
      type="button"
      onClick={() => onSelect(brand.key)}
      className="group flex flex-col items-center gap-4 overflow-hidden rounded-[28px] border border-white/10 bg-[#11100d] p-6 text-left transition duration-300 hover:-translate-y-1 hover:border-[#c9a85c]/40 hover:bg-[#16120f]"
    >
      <div className="flex h-32 w-32 items-center justify-center overflow-hidden rounded-3xl border border-white/10 bg-[#0f0b08] p-4">
        <img
          src={brand.logo}
          alt={`${brand.title} logo`}
          className="h-full w-full object-contain"
        />
      </div>
      <div className="text-left">
        <h3 className="text-xl font-semibold text-[#f5ede0]">{brand.title}</h3>
        <p className="mt-2 text-sm leading-6 text-[#d9cbae]">{brand.subtitle}</p>
      </div>
    </button>
  );
}
